(async () => {
  const url = 'https://i.weread.qq.com/shelf/sync?synckey=0&lectureSynckey=0';
  const res = await fetch(url, { credentials: 'include' });
  if (!res.ok) throw new Error('HTTP ' + res.status);
  const data = await res.json();
  const books = data.books || [];
  return books.map(item => {
    const info = item.bookInfo || {};
    return {
      title: info.title || item.title || '',
      author: info.author || item.author || '',
      progress: item.readingProgress != null ? item.readingProgress + '%' : '-',
      bookId: item.bookId || info.bookId || ''
    };
  });
})()
